using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };

            var sut = new PaginatedList<int>(items, 10, 2, 3);

            Assert.AreEqual(2, sut.PageIndex);
            Assert.AreEqual(4, sut.TotalPages); // ceil(10/3) = 4
            CollectionAssert.AreEqual(items, sut.ToList());
        }

        [TestMethod]
        [DataRow(1, false, DisplayName = "First page has no previous")]
        [DataRow(2, true, DisplayName = "Second page has previous")]
        [DataRow(3, true, DisplayName = "Third page has previous")]
        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            var sut = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
            Assert.AreEqual(expected, sut.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 3, true, DisplayName = "First of three pages has next")]
        [DataRow(3, 3, false, DisplayName = "Last page has no next")]
        [DataRow(2, 3, true, DisplayName = "Middle page has next")]
        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
        {
            var sut = new PaginatedList<int>(new List<int>(), totalPages * 5, pageIndex, 5);
            Assert.AreEqual(expected, sut.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(11, result.First());
            Assert.AreEqual(20, result.Last());
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(2, result.TotalPages);
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(1, result.First());
        }

        [TestMethod]
        public void Create_LastPartialPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(11, result.First());
            Assert.AreEqual(15, result.Last());
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_SinglePage_NoPreviousOrNext()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(5, result.Count);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        // Each test creates its own service but shares the static queue,
        // so we drain the queue before each test to ensure isolation.
        [TestInitialize]
        public void Setup()
        {
            using var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }

        [TestMethod]
        public void SendNotification_EnqueuesNotification()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "1", EntityOperation.CREATE, "admin");

            var notification = sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "admin");

            var notification = sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("Chemistry"));
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_IncludesIdInMessage()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("42"));
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "created", DisplayName = "CREATE operation")]
        [DataRow(EntityOperation.UPDATE, "updated", DisplayName = "UPDATE operation")]
        [DataRow(EntityOperation.DELETE, "deleted", DisplayName = "DELETE operation")]
        public void SendNotification_GeneratesCorrectMessage(EntityOperation operation, string expectedVerb)
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "1", "John Doe", operation);

            var notification = sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains(expectedVerb),
                $"Message '{notification.Message}' should contain '{expectedVerb}'");
        }

        [TestMethod]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = sut.ReceiveNotification();
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_WhenEmpty_ReturnsNull()
        {
            using var sut = new NotificationService();

            var result = sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "1", EntityOperation.CREATE);
            sut.SendNotification("Course", "2", EntityOperation.UPDATE);

            var first = sut.ReceiveNotification();
            var second = sut.ReceiveNotification();

            Assert.AreEqual("Student", first.EntityType);
            Assert.AreEqual("Course", second.EntityType);
        }

        [TestMethod]
        public void ReceiveNotification_DequeuesOnce_SubsequentCallReturnsNull()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "1", EntityOperation.CREATE);
            sut.ReceiveNotification();

            Assert.IsNull(sut.ReceiveNotification());
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            using var sut = new NotificationService();

            // MarkAsRead is a no-op for in-memory implementation; verify it doesn't throw
            sut.MarkAsRead(1);
            sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            var sut = new NotificationService();
            sut.Dispose();
            // Second dispose should also be safe
            sut.Dispose();
        }
    }
}

