using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static SchoolContext CreateSeeded(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructor = new Instructor
            {
                ID = 1,
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = new DateTime(1995, 3, 11)
            };
            context.Instructors.Add(instructor);

            var department = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 1
            };
            context.Departments.Add(department);

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            context.Courses.Add(course);

            var students = new[]
            {
                new Student
                {
                    ID = 1,
                    FirstMidName = "Carson",
                    LastName = "Alexander",
                    EnrollmentDate = new DateTime(2010, 9, 1)
                },
                new Student
                {
                    ID = 2,
                    FirstMidName = "Meredith",
                    LastName = "Alonso",
                    EnrollmentDate = new DateTime(2012, 9, 1)
                },
                new Student
                {
                    ID = 3,
                    FirstMidName = "Arturo",
                    LastName = "Anand",
                    EnrollmentDate = new DateTime(2013, 9, 1)
                }
            };
            context.Students.AddRange(students);

            context.Enrollments.Add(new Enrollment
            {
                EnrollmentID = 1,
                StudentID = 1,
                CourseID = 1050,
                Grade = Grade.A
            });

            context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            });

            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            });

            context.SaveChanges();
        }
    }
}

