    [TestClass]
    public sealed class NotificationsControllerTests
    {
        [TestInitialize]
        public void Setup()
        {
            // Drain the shared static queue for isolation
            using var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            using var context = TestDbContextFactory.Create();
            using var sut = new NotificationsController(context);

            var result = sut.Index();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void GetNotifications_WhenEmpty_ReturnsSuccessWithZeroCount()
        {
            using var context = TestDbContextFactory.Create();
            using var sut = new NotificationsController(context);

            var result = sut.GetNotifications();

            Assert.IsNotNull(result);
            var json = result.Value;
            Assert.IsNotNull(json);

            var successProp = json.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(json));

            var countProp = json.GetType().GetProperty("count");
            Assert.AreEqual(0, countProp.GetValue(json));
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            using var svc = new NotificationService();
            svc.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");
            svc.SendNotification("Course", "2", "Chemistry", EntityOperation.UPDATE, "admin");

            using var context = TestDbContextFactory.Create();
            using var sut = new NotificationsController(context);

            var result = sut.GetNotifications();
            var json = result.Value;

            var countProp = json.GetType().GetProperty("count");
            Assert.AreEqual(2, countProp.GetValue(json));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            using var context = TestDbContextFactory.Create();
            using var sut = new NotificationsController(context);

            var result = sut.MarkAsRead(1);

            Assert.IsNotNull(result);
            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            Assert.AreEqual(true, successProp.GetValue(json));
        }
    }
}
