using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Models
{
    [TestClass]
    public sealed class PersonTests
    {
        [TestMethod]
        [DataRow("Doe", "John", "Doe, John", DisplayName = "Standard name")]
        [DataRow("Smith", "Jane", "Smith, Jane", DisplayName = "Another name")]
        [DataRow("O'Connor", "Mary", "O'Connor, Mary", DisplayName = "Name with apostrophe")]
        public void FullName_ReturnsLastNameCommaFirstName(string lastName, string firstName, string expected)
        {
            var student = new Student { LastName = lastName, FirstMidName = firstName };

            Assert.AreEqual(expected, student.FullName);
        }
    }

    [TestClass]
    public sealed class ErrorViewModelTests
    {
        [TestMethod]
        public void ShowRequestId_WhenRequestIdIsSet_ReturnsTrue()
        {
            var model = new ErrorViewModel { RequestId = "abc-123" };
            Assert.IsTrue(model.ShowRequestId);
        }

        [TestMethod]
        [DataRow(null, DisplayName = "Null")]
        [DataRow("", DisplayName = "Empty")]
        public void ShowRequestId_WhenRequestIdIsNullOrEmpty_ReturnsFalse(string requestId)
        {
            var model = new ErrorViewModel { RequestId = requestId };
            Assert.IsFalse(model.ShowRequestId);
        }
    }
}

