using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        [TestInitialize]
        public void Setup()
        {
            // Drain the shared static queue for test isolation
            using var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }

        [TestMethod]
        public void SendNotification_EnqueuesNotification()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "1", EntityOperation.CREATE, "admin");

            var notification = sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "admin");

            var notification = sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("Chemistry"));
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_IncludesIdInMessage()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("42"));
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "created", DisplayName = "CREATE operation")]
        [DataRow(EntityOperation.UPDATE, "updated", DisplayName = "UPDATE operation")]
        [DataRow(EntityOperation.DELETE, "deleted", DisplayName = "DELETE operation")]
        public void SendNotification_GeneratesCorrectMessage(EntityOperation operation, string expectedVerb)
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "1", "John Doe", operation);

            var notification = sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains(expectedVerb),
                $"Message '{notification.Message}' should contain '{expectedVerb}'");
        }

        [TestMethod]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = sut.ReceiveNotification();
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_WhenEmpty_ReturnsNull()
        {
            using var sut = new NotificationService();

            var result = sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "1", EntityOperation.CREATE);
            sut.SendNotification("Course", "2", EntityOperation.UPDATE);

            var first = sut.ReceiveNotification();
            var second = sut.ReceiveNotification();

            Assert.AreEqual("Student", first.EntityType);
            Assert.AreEqual("Course", second.EntityType);
        }

        [TestMethod]
        public void ReceiveNotification_DequeuesOnce_SubsequentCallReturnsNull()
        {
            using var sut = new NotificationService();

            sut.SendNotification("Student", "1", EntityOperation.CREATE);
            sut.ReceiveNotification();

            Assert.IsNull(sut.ReceiveNotification());
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            using var sut = new NotificationService();
            sut.MarkAsRead(1);
            sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            var sut = new NotificationService();
            sut.Dispose();
            sut.Dispose();
        }
    }
}

