+            using var sut = new NotificationService();
+
+            var result = sut.ReceiveNotification();
+
+            Assert.IsNull(result);
+        }
+
+        [TestMethod]
+        public void ReceiveNotification_ReturnsFIFOOrder()
+        {
+            using var sut = new NotificationService();
+
+            sut.SendNotification("Student", "1", EntityOperation.CREATE);
+            sut.SendNotification("Course", "2", EntityOperation.UPDATE);
+
+            var first = sut.ReceiveNotification();
+            var second = sut.ReceiveNotification();
+
+            Assert.AreEqual("Student", first.EntityType);
+            Assert.AreEqual("Course", second.EntityType);
+        }
+
+        [TestMethod]
+        public void ReceiveNotification_DequeuesOnce_SubsequentCallReturnsNull()
+        {
+            using var sut = new NotificationService();
+
+            sut.SendNotification("Student", "1", EntityOperation.CREATE);
+            sut.ReceiveNotification();
+
+            Assert.IsNull(sut.ReceiveNotification());
+        }
+
+        [TestMethod]
+        public void MarkAsRead_DoesNotThrow()
+        {
+            using var sut = new NotificationService();
+            sut.MarkAsRead(1);
+            sut.MarkAsRead(999);
+        }
+
+        [TestMethod]
+        public void Dispose_DoesNotThrow()
+        {
+            var sut = new NotificationService();
+            sut.Dispose();
+            sut.Dispose();
+        }
+    }
+}
