        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            using var context = TestDbContextFactory.Create();
            using var sut = new HomeController(context);

            var result = sut.Index();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void Contact_ReturnsViewWithMessage()
        {
            using var context = TestDbContextFactory.Create();
            using var sut = new HomeController(context);

            var result = sut.Contact() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", sut.ViewBag.Message);
        }

        [TestMethod]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            using var sut = new HomeController(context);

