using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _sut = new StudentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_ReturnsViewWithPaginatedStudents()
        {
            var result = _sut.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _sut.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Anand", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _sut.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Anand", model[0].LastName);
            Assert.AreEqual("Alexander", model[model.Count - 1].LastName);
        }

        [TestMethod]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _sut.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Alexander", model[0].LastName); // 2010
        }

        [TestMethod]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _sut.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Anand", model[0].LastName); // 2013
        }

        [TestMethod]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _sut.Index(null, null, "Alexander", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _sut.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Carson", model[0].FirstMidName);
        }

        [TestMethod]
        public void Index_SearchWithNoMatch_ReturnsEmptyList()
        {
            var result = _sut.Index(null, null, "Nonexistent", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void Index_NewSearchString_ResetsPageTo1()
        {
            var result = _sut.Index(null, null, "A", 3) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _sut.Index(null, "Alexander", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.Count);
        }

        [TestMethod]
        public void Index_SetsSortViewBags()
        {
            _sut.Index(null, null, null, null);

            Assert.AreEqual("name_desc", _sut.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _sut.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_WithDateSort_SetsDateSortParmToDateDesc()
        {
            _sut.Index("Date", null, null, null);

            Assert.AreEqual("date_desc", _sut.ViewBag.DateSortParm);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var result = _sut.Details(1) as ViewResult;

            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual("Alexander", student.LastName);
        }

        [TestMethod]
        public void Details_ValidId_IncludesEnrollments()
        {
            var result = _sut.Details(1) as ViewResult;
            var student = result.Model as Student;

            Assert.IsNotNull(student.Enrollments);
            Assert.AreEqual(1, student.Enrollments.Count);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_GET_ReturnsViewWithDefaultDate()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual(DateTime.Today, student.EnrollmentDate);
        }

        [TestMethod]
        public void Create_POST_ValidModel_SavesAndRedirects()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _sut.Create(student) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(4, _context.Students.Count());
        }

        [TestMethod]
        public void Create_POST_MinDateValue_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _sut.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(_sut.ModelState.IsValid);
        }

        [TestMethod]
        public void Create_POST_DateBelow1753_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1700, 1, 1)
            };

            var result = _sut.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_POST_InvalidModelState_ReturnsViewWithModel()
        {
            _sut.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _sut.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreSame(student, result.Model);
        }

        #endregion

        #region Edit

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Edit((int?)null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsViewWithStudent()
        {
            var result = _sut.Edit(1) as ViewResult;

            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.AreEqual("Alexander", student.LastName);
        }

        [TestMethod]
        public void Edit_GET_NonexistentId_ReturnsNotFound()
        {
            var result = _sut.Edit(999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_POST_ValidModel_UpdatesAndRedirects()
        {
            var student = _context.Students.Find(1);
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedStudent = new Student
            {
                ID = 1,
                FirstMidName = "Updated",
                LastName = "Alexander",
                EnrollmentDate = new DateTime(2010, 9, 1)
            };

            var result = _sut.Edit(updatedStudent) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_POST_MinDateValue_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _sut.Edit(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(_sut.ModelState.IsValid);
        }

        [TestMethod]
        public void Edit_POST_InvalidModelState_ReturnsViewWithModel()
        {
            _sut.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2010, 9, 1)
            };

            var result = _sut.Edit(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreSame(student, result.Model);
        }

        #endregion

        #region Delete

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsViewWithStudent()
        {
            var result = _sut.Delete(1) as ViewResult;

            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.AreEqual("Alexander", student.LastName);
        }

        [TestMethod]
        public void Delete_GET_NonexistentId_ReturnsNotFound()
        {
            var result = _sut.Delete(999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            var result = _sut.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Students.Count());
        }

        #endregion
    }
}

