            _envMock.Setup(e => e.WebRootPath).Returns("/tmp/wwwroot");
            _envMock.Setup(e => e.ContentRootPath).Returns("/tmp");
            _loggerMock = new Mock<ILogger<CoursesController>>();
            _sut = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_ReturnsViewWithCourses()
        {
