using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context;
        private InstructorsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _sut = new InstructorsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithInstructors()
        {
            var result = _sut.Index(null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Instructors);
            Assert.AreEqual(1, model.Instructors.Count());
        }

        [TestMethod]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _sut.Index(1, null) as ViewResult;

            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model.Courses);
            Assert.AreEqual(1, model.Courses.Count());
            Assert.AreEqual("Chemistry", model.Courses.First().Title);
        }

        [TestMethod]
        public void Index_WithInstructorIdAndCourseId_PopulatesEnrollments()
        {
            var result = _sut.Index(1, 1050) as ViewResult;

            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model.Enrollments);
            Assert.AreEqual(1, model.Enrollments.Count());
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _sut.Details(1) as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        [TestMethod]
        public void Details_NonexistentId_ReturnsNotFound()
        {
            var result = _sut.Details(999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_GET_ReturnsViewWithCourseData()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.IsNotNull(instructor.CourseAssignments);
            Assert.IsNotNull(_sut.ViewBag.Courses);
        }

        [TestMethod]
        public void Create_POST_ValidModel_SavesAndRedirects()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 15)
            };

            var result = _sut.Create(instructor, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Instructors.Count());
        }

        [TestMethod]
        public void Create_POST_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 15)
            };
            var selectedCourses = new[] { "1050" };

            var result = _sut.Create(instructor, selectedCourses) as RedirectToActionResult;

            Assert.IsNotNull(result);
            var saved = _context.Instructors.Where(i => i.LastName == "Instructor").Single();
            Assert.AreEqual(1, saved.CourseAssignments.Count);
        }

        [TestMethod]
        public void Create_POST_InvalidModelState_ReturnsViewWithModel()
        {
            _sut.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "New",
                HireDate = new DateTime(2020, 1, 15),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _sut.Create(instructor, null) as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreSame(instructor, result.Model);
        }

        #endregion

        #region Edit GET

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Edit((int?)null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsViewWithInstructor()
        {
            var result = _sut.Edit(1) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(_sut.ViewBag.Courses);
        }

        #endregion

        #region Delete

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsViewWithInstructor()
        {
            var result = _sut.Delete(1) as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        [TestMethod]
        public void Delete_GET_NonexistentId_ReturnsNotFound()
        {
            var result = _sut.Delete(999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            var result = _sut.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(0, _context.Instructors.Count());
        }

        [TestMethod]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            _sut.DeleteConfirmed(1);

            var dept = _context.Departments.Find(1);
            Assert.IsNull(dept.InstructorID);
        }

        #endregion
    }
}

