public static void SeedData(SchoolContext context)
{
    // Add students first (auto-generated IDs, no conflicts with instructor in TPH)
    var student1 = new Student
    {
        FirstMidName = "Carson",
        LastName = "Alexander",
        EnrollmentDate = new DateTime(2010, 9, 1)
    };
    var student2 = new Student
    {
        FirstMidName = "Meredith",
        LastName = "Alonso",
        EnrollmentDate = new DateTime(2012, 9, 1)
    };
    var student3 = new Student
    {
        FirstMidName = "Arturo",
        LastName = "Anand",
        EnrollmentDate = new DateTime(2013, 9, 1)
    };
    context.Students.AddRange(student1, student2, student3);
    context.SaveChanges();

    var instructor = new Instructor
    {
        FirstMidName = "Kim",
        LastName = "Abercrombie",
        HireDate = new DateTime(1995, 3, 11)
    };
    context.Instructors.Add(instructor);
    context.SaveChanges();

    var department = new Department
    {
        DepartmentID = 1,
        Name = "Engineering",
        Budget = 350000,
        StartDate = new DateTime(2007, 9, 1),
        InstructorID = instructor.ID
    };
    context.Departments.Add(department);
    context.SaveChanges();

    var course = new Course
    {
        CourseID = 1050,
        Title = "Chemistry",
        Credits = 3,
        DepartmentID = department.DepartmentID
    };
    context.Courses.Add(course);
    context.SaveChanges();

    context.Enrollments.Add(new Enrollment
    {
        StudentID = student1.ID,
        CourseID = course.CourseID,
